mapper.sql:
tenant_id = #{tenantId}

    and (lower(alert_key) like concat('%', lower(#{keyword}), '%')
    or lower(object_code) like concat('%', lower(#{keyword}), '%')
    or lower(object_name) like concat('%', lower(#{keyword}), '%')
    or lower(message) like concat('%', lower(#{keyword}), '%'))

and current_level = #{level}
and status = #{status}
and object_type = #{objectType}
and topology_id = #{topologyId}
and topology_element_id = #{topologyElementId}

